const idea = $input.first().json;
const runId = $('Set Run ID').first().json.run_id;
const iteration = $('Set Run ID').first().json.iteration || 0;

// Map source URL path prefix to category
const categoryMap = [
  { prefix: '/osek-patur', cat: 'osek-patur' },
  { prefix: '/osek-murshe', cat: 'osek-murshe' },
  { prefix: '/hevra-bam', cat: 'hevra-bam' },
  { prefix: '/sgirat-tikim', cat: 'sgirat-tikim' },
  { prefix: '/guides', cat: 'guides' },
  { prefix: '/misui', cat: 'misui' },
  { prefix: '/hashbonaut', cat: 'hashbonaut' },
  { prefix: '/mishpati', cat: 'mishpati' },
  { prefix: '/shivuk', cat: 'shivuk' },
  { prefix: '/tech', cat: 'tech' },
  { prefix: '/mimun', cat: 'mimun' },
  { prefix: '/miktzoa', cat: 'miktzoa' },
  { prefix: '/compare', cat: 'compare' }
];

const sourceUrl = idea.source_page_url || '';
let category = 'guides'; // default
for (const mapping of categoryMap) {
  if (sourceUrl.startsWith(mapping.prefix)) {
    category = mapping.cat;
    break;
  }
}

// Slug will be generated by the LLM as slug_english field.
// Use idea id as temporary placeholder — will be overridden after Parse Article JSON.
const slugPlaceholder = 'article-' + idea.id;

return [{ json: {
  idea_id: idea.id,
  opportunity_id: idea.opportunity_id,
  source_page_url: idea.source_page_url,
  target_query: idea.target_query,
  suggested_article_title: idea.suggested_article_title,
  search_intent: idea.search_intent,
  suggested_angle: idea.suggested_angle,
  why_it_matters: idea.why_it_matters,
  internal_links: idea.internal_links,
  category,
  slug: slugPlaceholder,
  run_id: runId,
  iteration
}}];

const data = $input.first().json;
const today = new Date().toISOString().split('T')[0];
const internalLinksRaw = data.internal_links;
let internalLinksArr = [];
try {
  internalLinksArr = typeof internalLinksRaw === 'string' ? JSON.parse(internalLinksRaw) : (internalLinksRaw || []);
} catch(e) { internalLinksArr = []; }

const relatedSlugs = ['how-to-open','cost','faq','taxes','accountant','bituach-leumi','rights','management','income-ceiling','status-change','tax-reporting'];

const prompt = `אתה כותב תוכן SEO מקצועי בעברית עבור פורטל עסקי ישראלי בשם פרפקט וואן (perfect1.co.il).

משימה: כתוב מאמר SEO מקיף ומלא בנושא: "${data.suggested_article_title}"

פרטי הביטוי:
- ביטוי ראשי: ${data.target_query}
- כוונת חיפוש: ${data.search_intent}
- זווית: ${data.suggested_angle}
- קטגוריה: ${data.category}
- קישורים פנימיים מוצעים: ${JSON.stringify(internalLinksArr)}

=== דרישות חובה — אי-עמידה = FAIL ===

1. slug_english: צור slug קצר ותיאורי באנגלית, 2-5 מילים, kebab-case (לדוגמה: receipt-guide, bituach-leumi-guide, invoice-types). **אל תתרגם עברית לאנגלית — בחר שם משמעותי.**
2. sections: בדיוק 10-12 sections. כל section מינימום 150 מילים. סה\"כ המאמר: לפחות 1,800 מילים.
3. toc: id של כל entry חייב להתאים בדיוק ל-id של ה-section המתאים. אסור placeholder כמו section-id-1.
4. author: חייב להיות בדיוק {"name":"צוות פרפקט וואן","role":"מומחי עסקים"}. אל תמציא שם אחר.
5. FAQ: 5 שאלות. כל תשובה 50-80 מילים.
6. relatedArticles: בחר 3-4 slugs אמיתיים מהרשימה: ${relatedSlugs.join(', ')} — category: ${data.category}.
7. entities: המילים "רשות המסים", "מע\"מ", "ביטוח לאומי", "מס הכנסה" — כל אחת חייבת להופיע לפחות 3 פעמים במאמר.
8. מספרים: לפחות 8 מספרים/סכומים/אחוזים ספציפיים בשקלים ו-2026 (לדוגמה: 120,000₪, 17%, 2026, 175₪ לחודש).
9. answerBlock ב-section הראשון: 40-60 מילים בדיוק — תשובה ישירה ל-"${data.target_query}".
10. section מסוג cta-inline אחד עם הצעה לפנות לפרפקט וואן.

דוגמה למבנה תקין (מ-how-to-open.json):
{
  "slug": "[slug_english שייצור כאן]",
  "category": "${data.category}",
  "slug_english": "[2-5 words kebab-case English]",
  "metaTitle": "[ביטוי ראשי + | פרפקט וואן, מקסימום 60 תווים]",
  "metaDescription": "[140-155 תווים, ביטוי ראשי + CTA: למד/קרא/גלה]",
  "keywords": ["${data.target_query}", "ביטוי 2", "ביטוי 3", "ביטוי 4", "long-tail 5"],
  "heroTitle": "[H1 עד 70 תווים, כולל ביטוי ראשי]",
  "heroSubtitle": "[1-2 משפטי סיכום]",
  "publishDate": "${today}",
  "updatedDate": "${today}",
  "author": {"name": "צוות פרפקט וואן", "role": "מומחי עסקים"},
  "readTime": 12,
  "toc": [{"id": "intro", "title": "מה זה..."}, ... (id = id של section המתאים)],
  "sections": [
    {"id": "intro", "type": "text", "title": "...", "answerBlock": "[40-60 מילים]", "content": "[150+ מילים]"},
    ... (10-12 sections סה\"כ)
  ],
  "relatedArticles": [{"slug": "how-to-open", "category": "${data.category}", "title": "..."}, ...],
  "faq": [{"question": "...", "answer": "[50-80 מילים]"}, ... (5 שאלות)]
}

section types מותרים: text | list | steps | callout | faq | quote | comparison | cta-inline

החזר ONLY JSON תקני — ללא markdown fences, ללא טקסט לפני או אחרי.`;

return [{ json: {
  ...data,
  prompt,
  today
}}];

const claudeResponse = $input.first().json;
const upstream = $('Build Writer Prompt').first().json;

let article = null;
try {
  const rawText = claudeResponse.content[0].text.trim();
  // Strip markdown fences if GPT/Claude added them despite instructions
  const cleaned = rawText
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();
  article = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Failed to parse LLM JSON response: ' + e.message);
}

// Use slug_english from the article (LLM-generated) instead of Hebrew transliteration.
// Validate it looks like a valid kebab-case English slug.
function sanitizeSlug(s) {
  if (!s || typeof s !== 'string') return null;
  const cleaned = s.toLowerCase().replace(/[^a-z0-9-]/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '');
  return cleaned.length >= 2 ? cleaned.slice(0, 60) : null;
}

const llmSlug = sanitizeSlug(article.slug_english || article.slug);
// Fallback to idea id only if LLM gave garbage
const finalSlug = llmSlug || ('article-' + upstream.idea_id);

// Force correct author — do not trust LLM output
article.author = { name: 'צוות פרפקט וואן', role: 'מומחי עסקים' };

// Force today's dates
const today = upstream.today || new Date().toISOString().split('T')[0];
article.publishDate = today;
article.updatedDate = today;

return [{ json: {
  article,
  idea_id: upstream.idea_id,
  opportunity_id: upstream.opportunity_id,
  target_query: upstream.target_query,
  suggested_article_title: upstream.suggested_article_title,
  category: upstream.category,
  slug: finalSlug,
  run_id: upstream.run_id,
  iteration: upstream.iteration || 0,
  today
}}];

const input = $input.first().json;
const { article, target_query } = input;
const failures = [];
let seoScore = 0;
let aeoScore = 0;
let geoScore = 0;

// =====================
// SEO — 40 points
// =====================

// metaTitle: valid + ≤60 chars (10)
// Note: Hebrew contains target_query — check presence directly without lowercasing (Hebrew is case-neutral)
const metaTitle = article.metaTitle || '';
const titleContainsQuery = metaTitle.includes(target_query || '');
if (metaTitle && metaTitle.length <= 60 && titleContainsQuery) {
  seoScore += 10;
} else {
  if (!metaTitle) failures.push('metaTitle missing');
  else if (metaTitle.length > 60) failures.push(`metaTitle too long (${metaTitle.length} chars, max 60)`);
  else failures.push('metaTitle does not contain target_query');
}

// metaDescription: ≤155 chars + contains target_query + CTA (10)
const metaDesc = article.metaDescription || '';
const ctaWords = ['למד', 'קרא', 'גלה', 'בדוק', 'השווה', 'הורד', 'קבל', 'פנה', 'התחל'];
const hasCta = ctaWords.some(w => metaDesc.includes(w));
const descContainsQuery = metaDesc.includes(target_query || '');
if (metaDesc && metaDesc.length <= 155 && descContainsQuery && hasCta) {
  seoScore += 10;
} else {
  if (!metaDesc) failures.push('metaDescription missing');
  else if (metaDesc.length > 155) failures.push(`metaDescription too long (${metaDesc.length} chars, max 155)`);
  else if (!descContainsQuery) failures.push('metaDescription does not contain target_query');
  else if (!hasCta) failures.push('metaDescription missing CTA word');
}

// Word count ≥1500 (10)
const sections = article.sections || [];
let totalWords = 0;
for (const s of sections) {
  const texts = [];
  if (s.content) texts.push(s.content);
  if (s.answerBlock) texts.push(s.answerBlock);
  if (s.description) texts.push(s.description);
  if (s.items) s.items.forEach(i => { if (i.description) texts.push(i.description); if (i.title) texts.push(i.title); });
  if (s.steps) s.steps.forEach(i => { if (i.description) texts.push(i.description); });
  totalWords += texts.join(' ').split(/\s+/).filter(Boolean).length;
}
if (totalWords >= 1500) {
  seoScore += 10;
} else {
  failures.push(`Word count too low: ${totalWords} words (min 1500)`);
}

// Structure: ≥10 sections, heroTitle exists (H1), TOC exists, ≥3 relatedArticles (10)
const hasHeroTitle = !!(article.heroTitle);
const hasToc = Array.isArray(article.toc) && article.toc.length >= 8;
const hasRelated = Array.isArray(article.relatedArticles) && article.relatedArticles.length >= 3;
const hasSections = sections.length >= 10;
if (hasSections && hasHeroTitle && hasToc && hasRelated) {
  seoScore += 10;
} else {
  if (!hasSections) failures.push(`Not enough sections: ${sections.length} (min 10)`);
  if (!hasHeroTitle) failures.push('heroTitle (H1) missing');
  if (!hasToc) failures.push(`TOC too short: ${(article.toc||[]).length} entries (min 8)`);
  if (!hasRelated) failures.push(`relatedArticles too few: ${(article.relatedArticles || []).length} (min 3)`);
}

// =====================
// AEO — 30 points
// =====================

// FAQ: ≥5 questions (10)
const faq = article.faq || [];
if (faq.length >= 5) {
  aeoScore += 10;
} else {
  failures.push(`FAQ too few: ${faq.length} questions (min 5)`);
}

// FAQ answer length: each 40-80 words (10)
const answerLengths = faq.map(f => (f.answer || '').split(/\s+/).filter(Boolean).length);
const allAnswersOk = answerLengths.every(l => l >= 40 && l <= 90);
if (faq.length >= 5 && allAnswersOk) {
  aeoScore += 10;
} else if (faq.length >= 5) {
  const bad = answerLengths.filter(l => l < 40 || l > 90);
  failures.push(`${bad.length} FAQ answers outside 40-80 word range (found: ${answerLengths.join(', ')})`);
}

// Direct answer: first non-callout section has answerBlock 40-70 words (10)
const firstContentSection = sections.find(s => s.type !== 'callout' && s.type !== 'cta-inline');
const answerBlock = firstContentSection ? (firstContentSection.answerBlock || '') : '';
const answerWordCount = answerBlock.split(/\s+/).filter(Boolean).length;
if (answerBlock && answerWordCount >= 30 && answerWordCount <= 80) {
  aeoScore += 10;
} else {
  if (!answerBlock) failures.push('answerBlock missing in first content section');
  else failures.push(`answerBlock length ${answerWordCount} words (target 40-70)`);
}

// =====================
// GEO — 30 points
// =====================

const allText = JSON.stringify(article);

// Entity mentions: ≥4 of the authority entities must appear (10)
// Check each entity appears AT LEAST 3 times in full text
const entities = ['רשות המסים', 'מעמ', 'ביטוח לאומי', 'מס הכנסה'];
const entityCounts = entities.map(e => {
  // Count occurrences (JSON stringify may escape quotes so check without quotes in key)
  const escaped = e.replace(/"/g, '');
  const regex = new RegExp(escaped, 'g');
  const matches = allText.match(regex) || [];
  return { entity: e, count: matches.length };
});
const entitiesWithMin3 = entityCounts.filter(ec => ec.count >= 3);
if (entitiesWithMin3.length >= 3) {
  geoScore += 10;
} else {
  const insufficient = entityCounts.filter(ec => ec.count < 3).map(ec => `${ec.entity}(${ec.count}x)`);
  failures.push(`Entities appear fewer than 3 times each: ${insufficient.join(', ')} — need ≥3 entities each with ≥3 mentions`);
}

// Concrete numbers: ≥8 (10)
const numberMatches = allText.match(/(20\d{2}|\d[\d,]*\s*[₪%]|\d+\s*(ש"ח|אחוז|ימים|שנים|חודשים))/g) || [];
if (numberMatches.length >= 8) {
  geoScore += 10;
} else {
  failures.push(`Not enough concrete numbers/amounts: ${numberMatches.length} found (min 8)`);
}

// E-E-A-T: correct author name + updatedDate + keywords ≥4 (10)
const authorName = article.author && article.author.name;
const correctAuthor = authorName === 'צוות פרפקט וואן';
const hasUpdated = !!(article.updatedDate);
const hasKeywords = Array.isArray(article.keywords) && article.keywords.length >= 4;
if (correctAuthor && hasUpdated && hasKeywords) {
  geoScore += 10;
} else {
  if (!correctAuthor) failures.push(`Wrong author: "${authorName}" (must be "צוות פרפקט וואן")`);
  if (!hasUpdated) failures.push('updatedDate missing');
  if (!hasKeywords) failures.push(`keywords too few: ${(article.keywords || []).length} (min 4)`);
}

// =====================
// Final score — STRICT: passed = score >= 90 AND zero failures
// =====================
const score = seoScore + aeoScore + geoScore;
// Bug fix: passed must require BOTH conditions — score threshold AND no failures.
// Previously this could pass at score=30 if the failure array was somehow empty.
const passed = (score >= 90) && (failures.length === 0);

return [{ json: {
  ...input,
  gate: {
    score,
    breakdown: { seo: seoScore, aeo: aeoScore, geo: geoScore },
    failures,
    passed
  }
}}];

const input = $input.first().json;
const currentIteration = (input.iteration || 0) + 1;
const failures = input.gate.failures || [];
const score = input.gate.score;

if (currentIteration > 3) {
  // Signal to dismiss after 3 failed attempts
  return [{ json: { ...input, iteration: currentIteration, should_dismiss: true }}];
}

const revisionPrompt = `המאמר שכתבת נדחה על ידי מערכת Quality Gate.

ציון שהתקבל: ${score}/100 (נדרש: 90+)

בעיות שנמצאו:
${failures.map((f, i) => `${i+1}. ${f}`).join('\n')}

אנא תקן את כל הבעיות הנ\"ל וחזור עם ה-JSON המלא של המאמר, מתוקן.
חזור ONLY JSON תקני (ללא markdown fences, ללא טקסט לפני או אחרי).

המאמר הנוכחי:
${JSON.stringify(input.article, null, 2)}`;

return [{ json: {
  ...input,
  iteration: currentIteration,
  should_dismiss: false,
  revision_prompt: revisionPrompt
}}];

