SET status = 'dismissed', notes = 'QA failed after 3 attempts. Last score: {{ $json.gate.score }}/100'
WHERE id = {{ $json.idea_id }};

parameters.jsCode:
const claudeResponse = $input.first().json;
const upstream = $('Revision Prompt').first().json;

let article = null;
try {
  const rawText = claudeResponse.content[0].text.trim();
  const cleaned = rawText
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();
  article = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Revision parse failed: ' + e.message);
}

// Always enforce correct author and today dates — never trust LLM output
article.author = { name: 'צוות פרפקט וואן', role: 'מומחי עסקים' };
const today = upstream.today || new Date().toISOString().split('T')[0];
article.publishDate = today;
article.updatedDate = today;

return [{ json: {
  article,
  idea_id: upstream.idea_id,
  opportunity_id: upstream.opportunity_id,
  target_query: upstream.target_query,
  suggested_article_title: upstream.suggested_article_title,
  category: upstream.category,
  slug: upstream.slug,
  run_id: upstream.run_id,
  iteration: upstream.iteration,
  today
}}];

const input = $input.first().json;
const { article, category, slug, suggested_article_title, gate } = input;

// Ensure slug/category on the article are correct
article.slug = slug;
article.category = category;

const jsonString = JSON.stringify(article, null, 2);
const base64Content = Buffer.from(jsonString).toString('base64');
const filePath = `src/content/${category}/${slug}.json`;
const commitMessage = `Feat: Auto-published article — ${suggested_article_title}`;

return [{ json: {
  ...input,
  base64Content,
  filePath,
  commitMessage,
  scoreNote: `SEO/AEO/GEO score: ${gate.score}/100 (SEO:${gate.breakdown.seo} AEO:${gate.breakdown.aeo} GEO:${gate.breakdown.geo})`
}}];

const githubResponse = $input.first().json;
const upstream = $('Prepare Commit').first().json;

// sha may be undefined if file doesn't exist yet (new article)
const existingSha = githubResponse.sha || null;

return [{ json: {
  ...upstream,
  existingSha
}}];

// NOTE: Sitemap update via GitHub API requires getting current SHA + content,
// then PUT with updated content. Implemented inline here.
// If this node fails, the article is still published — sitemap is non-blocking.

const upstream = $('Set SHA for Commit').first().json;
const { category, slug, today } = upstream;
const newUrl = `https://perfect1.co.il/${category}/${slug}`;
const newEntry = `  <url><loc>${newUrl}</loc><lastmod>${today}</lastmod><changefreq>monthly</changefreq><priority>0.7</priority></url>`;

// We'll fetch sitemap via separate HTTP nodes (see sticky note).
// For now, output what would be added so it can be manually added if needed.
return [{ json: {
  ...upstream,
  sitemap_entry_to_add: newEntry,
  sitemap_note: 'TODO: Add this entry to public/sitemap.xml'
}}];
